const response = await fetch("https://api.complianceguard.example.com/a2a", {
  method: "POST",
  headers: {
    "Content-Type": "application/json",
    "x-api-key": "YOUR_API_KEY",
  },
  body: JSON.stringify({
    jsonrpc: "2.0",
    method: "tasks/send",
    params: {
      id: "task-1",
      message: { role: "user", parts: [{ type: "text", text: "Check GDPR compliance: We store user emails indefinitely." }] },
      skillId: "check_regulation",
    },
    id: "1",
  }),
});
console.log(await response.json());
